commits.content:
:host {
  display: block;
  padding: 16px;
  font-family: 'Arial', sans-serif;

  h1 {
    font-size: 2rem;
    margin-bottom: 8px;
  }

  h2 {
    font-size: 1.5rem;
    margin-top: 24px;
    margin-bottom: 12px;
    border-bottom: 2px solid #eee;
    padding-bottom: 4px;
  }

  img.company-avatar {
    width: 120px;
    height: 120px;
    object-fit: cover; // giữ tỉ lệ ảnh
    border-radius: 50%;
    margin-bottom: 12px;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.2);
  }

  p {
    margin: 4px 0;
    line-height: 1.5;
  }

  a {
    color: #007bff;
    text-decoration: none;

    &:hover {
      text-decoration: underline;
    }
  }

  .job-list {
    display: flex;
    flex-direction: column;
    gap: 16px;

    .job-item {
      padding: 12px;
      border: 1px solid #eee;
      border-radius: 8px;
      transition: box-shadow 0.2s;

      &:hover {
        box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
      }

      h3 {
        margin: 0 0 8px 0;
        font-size: 1.2rem;
        color: #333;
      }

      p {
        margin: 2px 0;
        color: #555;
      }
    }
  }

  .pagination {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-top: 16px;
    gap: 8px;

    button {
      padding: 6px 12px;
      border: none;
      border-radius: 4px;
      background-color: #007bff;
      color: white;
      cursor: pointer;
      transition: background-color 0.2s;

      &:disabled {
        background-color: #ccc;
        cursor: not-allowed;
      }

      &:hover:not(:disabled) {
        background-color: #0056b3;
      }
    }

    span {
      font-weight: 500;
      color: #333;
    }
  }
}
